def process_order(order):
    if order['status'] != 'pending':
        return None
    total = 0
    for item in order['items']:
        if item['quantity'] <= 0:
            continue
        price = item['price']
        if item.get('discount'):
            price = price * (1 - item['discount'])
        if order.get('member'):
            price = price * 0.9
        total += price * item['quantity']
    if total > 100:
        shipping = 0
    else:
        shipping = 10
    order['total'] = total + shipping
    order['status'] = 'processed'
    return order

function checkAccess(user: User | null, doc: Doc | null): boolean {
  if (user) {
    if (user.active) {
      if (doc) {
        if (doc.owner === user.id) {
          return true;
        } else {
          if (doc.sharedWith.includes(user.id)) {
            return true;
