  }
}

def parse_iso_duration(value: str) -> timedelta:
    """Parse an ISO 8601 duration like 'PT1H30M' into a timedelta."""
    match = _ISO_DURATION_RE.fullmatch(value)
    if not match:
        raise ValueError(f"not an ISO 8601 duration: {value!r}")
    hours, minutes, seconds = (int(g or 0) for g in match.groups())
    return timedelta(hours=hours, minutes=minutes, seconds=seconds)

type Result<T, E> = { ok: true; value: T } | { ok: false; error: E };

export async function safeJson<T>(
  res: Response,
): Promise<Result<T, SyntaxError>> {
  try {
    const value = (await res.json()) as T;
    return { ok: true, value };
  } catch (err) {
    return { ok: false, error: err as SyntaxError };
  }
}

